// === AllFreeAlerts Auto-Poster: Pick items + generate posts ===
// Priority: NEW items first, then oldest recycled
// Settlements: no-proof-needed first

const items = $input.all().map(i => i.json);
const allItems = Array.isArray(items[0]) ? items[0] : items;

// --- Post history (stored in static data) ---
const staticData = $getWorkflowStaticData('global');
if (!staticData.postHistory) staticData.postHistory = [];
const history = staticData.postHistory;
const postedTitles = new Set(history.map(h => h.title));

function pickBest(candidates) {
  if (candidates.length === 0) return null;
  const neverPosted = candidates.filter(i => !postedTitles.has(i.title));
  if (neverPosted.length > 0) {
    const pick = neverPosted[Math.floor(Math.random() * neverPosted.length)];
    pick._pickReason = 'NEW';
    return pick;
  }
  const withDates = candidates.map(i => {
    const lastPost = history.filter(h => h.title === i.title).sort((a, b) => new Date(b.date) - new Date(a.date))[0];
    return { item: i, lastPosted: lastPost ? new Date(lastPost.date) : new Date(0) };
  }).sort((a, b) => a.lastPosted - b.lastPosted);
  const pick = withDates[0].item;
  pick._pickReason = 'RECYCLED';
  return pick;
}

// Pick 1 per category
const picks = [];
const sweepPick = pickBest(allItems.filter(i => i.category === 'Sweepstakes'));
if (sweepPick) picks.push(sweepPick);

const freebiePick = pickBest(allItems.filter(i => i.category === 'Freebies'));
if (freebiePick) picks.push(freebiePick);

// Settlements: no-proof first
const settlements = allItems.filter(i => i.category === 'Settlements');
const noProof = settlements.filter(i => i.proof_required === 'No' || i.proof_required === 'N/A');
const proofNeeded = settlements.filter(i => i.proof_required === 'Yes');
const unclear = settlements.filter(i => !i.proof_required || (i.proof_required !== 'No' && i.proof_required !== 'Yes' && i.proof_required !== 'N/A'));
let settlePick = pickBest(noProof);
if (settlePick) { settlePick._proofStatus = 'NO PROOF NEEDED'; }
else { settlePick = pickBest(unclear); if (settlePick) settlePick._proofStatus = 'PROOF UNKNOWN'; }
if (!settlePick) { settlePick = pickBest(proofNeeded); if (settlePick) settlePick._proofStatus = 'PROOF REQUIRED'; }
if (settlePick) picks.push(settlePick);

// --- Tweet templates (also used for X) ---
const tweetTemplates = {
  Sweepstakes: [
    (i) => `🎉 SWEEPSTAKES ALERT\n\n${i.title}\n\n${i.prize_summary ? i.prize_summary.slice(0,100)+'...' : 'Enter now for a chance to win!'}\n\n👉 allfreealerts.com\n\n#sweepstakes #giveaway #win #allfreealerts`,
    (i) => `Win something amazing today! 🏆\n\n${i.title}\n\nFind it on 👉 allfreealerts.com\n\n#entertowin #sweepstakes #contest #free`,
    (i) => `Don't miss this one 👀\n\n${i.title}\n\n${i.prize_summary ? i.prize_summary.slice(0,100) : 'Free to enter!'}\n\n👉 allfreealerts.com\n\n#giveaway #sweepstakes #win #allfreealerts`
  ],
  Freebies: [
    (i) => `🆓 FREE STUFF ALERT\n\n${i.title}\n\nNo purchase necessary. Get yours before it's gone!\n\n👉 allfreealerts.com\n\n#freestuff #freebie #freesample #allfreealerts`,
    (i) => `This is completely FREE 👇\n\n${i.title}\n\nNo credit card. No catch.\n\n👉 allfreealerts.com\n\n#free #freebie #freesample #freestuff`,
    (i) => `Today's freebie find 🎁\n\n${i.title}\n\nGrab it while supplies last 👉 allfreealerts.com\n\n#freebies #freestuff #savemoney #allfreealerts`
  ],
  Settlements: [
    (i) => `💰 CLASS ACTION ALERT\n\n${i.title}\n\n${i.payout ? '💵 Payout: ' + i.payout : 'You may be owed money!'}\n${i._proofStatus === 'NO PROOF NEEDED' ? '✅ No proof of purchase needed!\n' : ''}\nFile your claim 👉 allfreealerts.com\n\n#classaction #settlement #freemoney #allfreealerts`,
    (i) => `You might be owed money 💵\n\n${i.title}\n${i.payout ? '\n💰 ' + i.payout : ''}\n${i._proofStatus === 'NO PROOF NEEDED' ? '✅ No receipt needed!\n' : ''}\nCheck if you qualify 👉 allfreealerts.com\n\n#settlement #classaction #moneytok #allfreealerts`,
    (i) => `Don't leave money on the table!\n\n${i.title}\n${i.payout ? '\nPayout: ' + i.payout : ''}\n${i._proofStatus === 'NO PROOF NEEDED' ? '\n🙌 No proof needed — just file a claim!' : ''}\n\n👉 allfreealerts.com\n\n#classaction #freemoney #settlement`
  ]
};

// --- Instagram caption templates (longer, more hashtags) ---
const igTemplates = {
  Sweepstakes: [
    (i) => `🎉 SWEEPSTAKES ALERT 🎉\n\n${i.title}\n\n${i.prize_summary ? '🏆 ' + i.prize_summary : 'Enter now for a chance to win!'}\n\n👉 Link in bio — allfreealerts.com\n📱 Follow @allfreealerts for daily finds!\n\n#sweepstakes #giveaway #win #entertowin #contest #free #prizes #allfreealerts #sweepstakesalert #winprizes`,
    (i) => `WIN something amazing today! 🏆✨\n\n${i.title}\n\n${i.prize_summary ? i.prize_summary : 'Free to enter — no purchase necessary!'}\n\n👉 allfreealerts.com (link in bio)\n\n#sweepstakes #giveaway #winbig #freeprizes #entertowin #contest #allfreealerts #dailygiveaway #freestuff`
  ],
  Freebies: [
    (i) => `🆓 FREE STUFF ALERT 🆓\n\n${i.title}\n\nNo purchase necessary. No credit card. No catch.\nGet yours before it's gone!\n\n👉 Link in bio — allfreealerts.com\n📱 Follow @allfreealerts for daily freebies!\n\n#freestuff #freebie #freesample #free #nopurchasenecessary #freebies #savemoney #allfreealerts #freesamples #deals`,
    (i) => `This is completely FREE 👇🎁\n\n${i.title}\n\nGrab it while supplies last!\n\n👉 allfreealerts.com (link in bio)\n\n#free #freebie #freesample #freestuff #savemoney #frugal #allfreealerts #dailydeals #freebiesusa`
  ],
  Settlements: [
    (i) => `💰 CLASS ACTION SETTLEMENT 💰\n\n${i.title}\n\n${i.payout ? '💵 Payout: ' + i.payout + '\n' : 'You may be owed money!\n'}${i._proofStatus === 'NO PROOF NEEDED' ? '✅ No proof of purchase needed!\n' : ''}\nFile your claim today!\n👉 Link in bio — allfreealerts.com\n\n#classaction #settlement #freemoney #moneytok #refund #claim #allfreealerts #classactionsettlement #easymoney #nocatchfree`,
    (i) => `You might be owed money 💵💵\n\n${i.title}\n${i.payout ? '\n💰 ' + i.payout : ''}\n${i._proofStatus === 'NO PROOF NEEDED' ? '✅ No receipt needed — just file a claim!\n' : ''}\nCheck if you qualify 👉 allfreealerts.com\n\n#settlement #classaction #freemoney #moneyhack #allfreealerts #refund #claimyourmoney`
  ]
};

// --- Generate posts + QA ---
const posts = [];
for (const item of picks) {
  // Tweet text
  const catTweetTemplates = tweetTemplates[item.category] || tweetTemplates.Freebies;
  const tweetTemplate = catTweetTemplates[Math.floor(Math.random() * catTweetTemplates.length)];
  let tweetText = tweetTemplate(item);
  if (tweetText.length > 280) tweetText = tweetText.slice(0, 277) + '...';

  // IG caption (per-item, for single image posts)
  const catIgTemplates = igTemplates[item.category] || igTemplates.Freebies;
  const igTemplate = catIgTemplates[Math.floor(Math.random() * catIgTemplates.length)];
  const igCaption = igTemplate(item);

  // QA checks
  const errors = [];
  if (tweetText.length > 280) errors.push('Over 280 chars');
  if (!item.title || item.title.trim() === '') errors.push('Missing title');
  if (!tweetText.includes('allfreealerts.com')) errors.push('Missing link');
  if (!tweetText.includes('#')) errors.push('Missing hashtags');
  if (tweetText.includes('undefined') || tweetText.includes('null')) errors.push('Broken tweet text');
  if (igCaption.includes('undefined') || igCaption.includes('null')) errors.push('Broken IG text');
  if (errors.length > 0) continue;

  posts.push({
    category: item.category,
    title: item.title,
    prize_summary: item.prize_summary || '',
    payout: item.payout || '',
    tweetText: tweetText,
    igCaption: igCaption,
    link: item.link || 'https://allfreealerts.com',
    pickReason: item._pickReason,
    proofStatus: item._proofStatus || ''
  });
}

// --- Facebook post text (combined daily roundup) ---
let fbText = '🔥 Today\'s FREE Finds from AllFreeAlerts.com:\n\n';
for (const p of posts) {
  if (p.category === 'Sweepstakes') {
    fbText += `🎉 SWEEPSTAKES: ${p.title}\n`;
    if (p.prize_summary) fbText += `   ${p.prize_summary.slice(0, 100)}\n`;
  } else if (p.category === 'Freebies') {
    fbText += `🎁 FREE: ${p.title}\n`;
  } else if (p.category === 'Settlements') {
    fbText += `💰 SETTLEMENT: ${p.title}\n`;
    if (p.payout) fbText += `   Payout: ${p.payout}\n`;
    if (p.proofStatus === 'NO PROOF NEEDED') fbText += '   ✅ No proof needed!\n';
  }
  fbText += '\n';
}
fbText += '👉 See all deals at allfreealerts.com\n';
fbText += '📱 Follow us for daily alerts!';

// Save to history
const now = new Date().toISOString().split('T')[0];
for (const p of posts) {
  history.push({ title: p.title, category: p.category, date: now });
}
// Keep history manageable (last 500)
if (history.length > 500) {
  staticData.postHistory = history.slice(-500);
}

return [{
  json: {
    tweets: posts,
    igPosts: posts,
    fbText: fbText,
    postCount: posts.length
  }
}];

// Post each tweet to X/Twitter with OAuth 1.0a signing
const crypto = require('crypto');

const CONSUMER_KEY = 'hcHHkgItx9BJSC0lDzOxrBzKY';
const CONSUMER_SECRET = 'koo2rgcY5oghVHxTP6p01WNLtP22eitnp1kvMYO40Bmb0qZazP';
const ACCESS_TOKEN = '2037735445518229504-FI76g7VEpXu6LOn55wQ36OFnglh0yA';
const ACCESS_SECRET = '95iYsY2WZFcRSGmCpshYnnoY2Zpsy2XgGrYkHk2NJkwN4';

function percentEncode(str) {
  return encodeURIComponent(str).replace(/[!'()*]/g, c => '%' + c.charCodeAt(0).toString(16).toUpperCase());
}

function signRequest(method, url, params) {
  const sorted = Object.keys(params).sort().map(k => `${percentEncode(k)}=${percentEncode(params[k])}`).join('&');
  const base = `${method}&${percentEncode(url)}&${percentEncode(sorted)}`;
  const key = `${percentEncode(CONSUMER_SECRET)}&${percentEncode(ACCESS_SECRET)}`;
  return crypto.createHmac('sha1', key).update(base).digest('base64');
}

const data = $input.first().json;
const tweets = data.tweets || [];
const results = [];

for (const post of tweets) {
  const url = 'https://api.twitter.com/2/tweets';
  const oauthParams = {
    oauth_consumer_key: CONSUMER_KEY,
    oauth_nonce: crypto.randomBytes(16).toString('hex'),
    oauth_signature_method: 'HMAC-SHA1',
    oauth_timestamp: Math.floor(Date.now() / 1000).toString(),
    oauth_token: ACCESS_TOKEN,
    oauth_version: '1.0'
  };
  oauthParams.oauth_signature = signRequest('POST', url, oauthParams);
  const authHeader = 'OAuth ' + Object.keys(oauthParams).sort().map(k => `${percentEncode(k)}="${percentEncode(oauthParams[k])}"`).join(', ');

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: url,
      headers: { 'Authorization': authHeader, 'Content-Type': 'application/json' },
      body: JSON.stringify({ text: post.tweetText })
    });
    results.push({ category: post.category, status: 'posted', tweetId: resp.data?.id });
  } catch (e) {
    results.push({ category: post.category, status: 'failed', error: e.message });
  }
}

return [{ json: { ...data, tweetResults: results } }];

