const IG_USER_ID = '17841436221523604';
const ACCESS_TOKEN = 'EAASCIjhOZCgMBRCpmzEw6zXbZA1VSZABhvR1TtJABDEzqcFphAxtsYoK0bYEnBADmE7qRkCyHqne6aj5hd1nLMPMiopzb7llbZBlf9E9WJtUmrleRUBAMli0EUSuQEA7ol1GZCNNOO7webD02cHYCUDPzDFt9mpxnV0KIGODsckoWn6JZC1NXDF3Awmkf9MgZDZD';
const API_VERSION = 'v25.0';

// Category images hosted on allfreealerts.com/social/
// 3 variations per category for visual variety
const IMAGES = {
  Sweepstakes: [
    'https://allfreealerts.com/social/sweepstakes_1.png',
    'https://allfreealerts.com/social/sweepstakes_2.png',
