  ],
  Freebies: [
    'https://allfreealerts.com/social/freebies_1.png',
    'https://allfreealerts.com/social/freebies_2.png',
    'https://allfreealerts.com/social/freebies_3.png'
  ],
  Settlements: [
    'https://allfreealerts.com/social/settlements_1.png',
