    'https://allfreealerts.com/social/settlements_3.png'
  ]
};
const DEFAULT_IMAGE = 'https://allfreealerts.com/social/freebies_1.png';

const data = $input.first().json;
const posts = data.igPosts || [];

if (posts.length === 0) {
  return [{ json: { ...data, igResults: [{ status: 'skipped', reason: 'no posts' }] } }];
}

const igResults = [];

for (const post of posts) {
  try {
    // Pick a random category image
    const catImages = IMAGES[post.category] || IMAGES.Freebies;
    const imageUrl = catImages[Math.floor(Math.random() * catImages.length)];

    // Step 1: Create media container (form data for proper emoji encoding)
    const containerResp = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/${API_VERSION}/${IG_USER_ID}/media`,
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams({
        image_url: imageUrl,
        caption: post.igCaption,
        access_token: ACCESS_TOKEN
      }).toString()
    });

    const containerId = containerResp.id;

    // Step 2: Wait for container to be ready (poll status)
    let ready = false;
    let attempts = 0;
    while (!ready && attempts < 10) {
      await new Promise(resolve => setTimeout(resolve, 3000));
      const statusResp = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://graph.facebook.com/${API_VERSION}/${containerId}?fields=status_code&access_token=${ACCESS_TOKEN}`
      });
      if (statusResp.status_code === 'FINISHED') ready = true;
      else if (statusResp.status_code === 'ERROR') throw new Error('Container creation failed: ' + JSON.stringify(statusResp));
      attempts++;
    }

    if (!ready) throw new Error('Container not ready after 30s');

    // Step 3: Publish
    const publishResp = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/${API_VERSION}/${IG_USER_ID}/media_publish`,
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams({
        creation_id: containerId,
        access_token: ACCESS_TOKEN
      }).toString()
    });

    igResults.push({
      category: post.category,
      title: post.title,
      status: 'posted',
      mediaId: publishResp.id
    });
  } catch (e) {
    igResults.push({
      category: post.category,
      title: post.title,
      status: 'failed',
      error: e.message
    });
  }
}

return [{ json: { ...data, igResults } }];

